data class DriverModel(
    val driverInfo: DriverInfo,
    val crc8Check: Crc8Check? = null,
    val evChargerParam: EVChargerParam? = null
) {
    companion object {
        val EmptyChargerModel = DriverModel(
            driverInfo = DriverInfo(
                driverType = 24,
                mapping = 1,
                nfcDataBase64 = ""
            ),
        )
    }
}